const PiranhaMessage = require("../../PiranhaMessage");
const ByteArray = require("../../../ByteStream/ByteArray");
const SetPlayerNameMessageOkMessage = require("./SetPlayerNameMessageOkMessage");

class OwnHomeDataMessage extends PiranhaMessage {
  constructor(client) {
    super();
    this.id = 25865;
    this.client = client;
    this.version = 0;
  }

  async encode() {
    //69752372
    let user = this.client.user;
    this.writeInt(user.id.high);
    this.writeInt(user.id.low);
    this.writeInt(0);
    this.writeVInt(247);
    this.writeVInt(0);

    /*let deck = [
      26000026,
      26000015,
      26000012,
      26000000,
      26000004,
      26000005,
      26000006,
      26000007, //, 26000008, 26000009, 26000010, 26000011,
    ];*/

    let cards = [
      // 26000000, 26000001, 26000002, 26000003, 26000004, 26000005, 26000006,
      // 26000007, 26000001, 26000008, 26000009, 26000010,
    ];

    //add all troop cards
    for (let i = 0; i < 104; i++) {
      cards.push(26000000 + i);
    }

    //add all buildings cards
    for (let i = 0; i < 18; i++) {
      cards.push(27000000 + i);
    }

    //add all spell cards
    for (let i = 0; i < 27; i++) {
      cards.push(28000000 + i);
    }

    this.writeVInt(cards.length); //deck cards count

    //" 018cba80 00000000000100000000 018cba81 00000000000100000000 018cba85 00000000000100000000 01ab3f01 00000000000100000000 01ab3f00 00000000000100000000 018cba83 00000000000100000000 018cba8e 00000000000100000000 018cba92 0000000000010000000001

    // let cards = [
    //   26000000, 26000001, 26000005, 28000001, 28000000, 26000003, 26000014,
    //   26000018,
    // ];

    for (let card of cards) {
      this.writeInt(card);
      this.writeByte(5); //card level
      this.writeHex("000000000100000000");
    }

    this.writeByte(1);

    this.writeHex(
      "",
    );

    //this.writeHex("0000000b436c617373696320327632");
    this.writeString("Classic 2v2");

    this.writeHex("2780d0e3880d809eeda60d80d0e3880d809eeda60d0000000000000000");

    this.writeString("Classic 2v2");

    this.writeHex(
      "",
    );
    //this.writeHex("0801");

    this.writeByte(user.deck.length); //deck cards count
    this.writeByte(1);

    // this.writeHex(
    //   "018cba80018cba81018cba8501ab3f0101ab3f00018cba83018cba8e018cba92",
    // );

    for (let card of user.deck) {
      this.writeInt(card);
    }

    this.writeHex(
      "",
    );

    this.writeByte(0);
    this.writeByte(0);
    this.writeByte(0);
    this.writeByte(user.deck.length);
    this.writeByte(0);
    this.writeByte(255);
    // this.writeHex(
    //   "018cba8000000000000100000000018cba8100000000000100000000018cba850000000000010000000001ab3f010000000000010000000001ab3f0000000000000100000000018cba8300000000000100000000018cba8e00000000000100000000018cba9200000000000100000000",
    // );
    for (let card of user.deck) {
      this.writeInt(card);
      this.writeByte(15); //card level
      this.writeHex("000000000100000000");
    }

    this.writeHex(
      "08e18f40000001010800000008e18f400004000000007f000000007f00007f0300000000000000020100",
    );

    this.writeByte(3); //3 = name already ; set 1 = name set popup

    this.writeVInt(54000002);

    this.writeHex(
      "",
    );
    this.writeHex("03000000");
    this.writeByte(6); //6 = name not set ; 7 = name set ; 8 = clan + name not set ; 9 = clan + name set
    this.writeHex("0000000000");
    this.writeHex("000006000000010000000600000002000000");

    this.writeByte(6); //6 = don't show discord - 7 = show discord

    this.writeHex(
      "",
    );

    //00 00 00 0D 74 2E 6D 65 2F 6E 6F 74 68 69 6E 67 58
    this.writeString("dsc.gg/protections");

    this.writeHex(
      "",
    );
    this.writeHex("00000002007f");
    this.writeHex("00000000000000000000000000000903004c4b41");
    this.writeVInt(6767); //gold
    this.writeHex("004c4b420a004c4b430000000001004c4b480800000000");
    this.writeVInt(6768); //gems
    this.writeVInt(6769);
    this.writeHex(
      "000000000100000000000000050000010000000000965e0090e5e8860700ffffffff0000000000000000000000000000000000000000000000000080a7aa970d7f009ac992990d",
    );

    if (user.username !== "") {
      new SetPlayerNameMessageOkMessage(this.client, user.username).send();
    }
  }
}

module.exports = OwnHomeDataMessage;
